module RefModule(CLK, RST, Q);
input CLK, RST;
output [2:0] Q;
reg [2:0] Q;
reg [2:0] binary_counter;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST) begin
        binary_counter <= 0;
        Q <= 0;
    end else begin
        binary_counter <= binary_counter + 1;
        Q <= (binary_counter >> 1) ^ binary_counter; // Convert binary to gray code
    end
end

endmodule
